import{_ as s,o as e,c as i,a2 as n}from"./chunks/framework.LN3EJxkW.js";const b=JSON.parse('{"title":"ACID、MVCC、事务隔离、锁与死锁","description":"","frontmatter":{},"headers":[],"relativePath":"05-backend-data/notes/06-api-database/16-acid-isolation-mvcc-locks.md","filePath":"05-backend-data/notes/06-api-database/16-acid-isolation-mvcc-locks.md","lastUpdated":null}'),t={name:"05-backend-data/notes/06-api-database/16-acid-isolation-mvcc-locks.md"};function l(r,a,p,d,o,h){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="acid、mvcc、事务隔离、锁与死锁" tabindex="-1">ACID、MVCC、事务隔离、锁与死锁 <a class="header-anchor" href="#acid、mvcc、事务隔离、锁与死锁" aria-label="Permalink to &quot;ACID、MVCC、事务隔离、锁与死锁&quot;">​</a></h1><p>数据库事务把一组读写作为一个提交/回滚边界。ACID 描述事务提供的性质；隔离级别定义并发事务可观察的交错；PostgreSQL 通过 MVCC、行/表锁和可序列化冲突检测共同实现这些语义。</p><h2 id="_1-acid-逐项定义" tabindex="-1">1. ACID 逐项定义 <a class="header-anchor" href="#_1-acid-逐项定义" aria-label="Permalink to &quot;1. ACID 逐项定义&quot;">​</a></h2><ul><li>Atomicity（原子性）：事务中的变更一起提交或回滚。它不让外部 HTTP、邮件或另一个数据库自动加入原子边界。</li><li>Consistency（一致性）：事务把数据库从满足已声明不变量的状态带到另一个满足不变量的状态。数据库只能执行已编码的约束、触发器和事务逻辑，不能理解未表达的业务规则。</li><li>Isolation（隔离性）：并发执行的可见结果受隔离级别约束。它不是所有级别都等同串行执行。</li><li>Durability（持久性）：提交确认后的变更按配置承诺在故障后可恢复。<code>synchronous_commit</code>、复制与存储故障模型会改变具体保证。</li></ul><h2 id="_2-postgresql-mvcc-的核心" tabindex="-1">2. PostgreSQL MVCC 的核心 <a class="header-anchor" href="#_2-postgresql-mvcc-的核心" aria-label="Permalink to &quot;2. PostgreSQL MVCC 的核心&quot;">​</a></h2><p>MVCC 为行保存多个版本。事务读取由快照判断可见的版本，普通读取通常不阻塞普通写入，写入也不会覆盖其他快照仍需要的旧版本。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant T1 as Transaction 1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant DB as PostgreSQL MVCC</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant T2 as Transaction 2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T1-&gt;&gt;DB: 取得 snapshot，读取 version A</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T2-&gt;&gt;DB: UPDATE，创建 version B</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T2-&gt;&gt;DB: COMMIT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T1-&gt;&gt;DB: 同一/新语句读取（取决于隔离级别）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    DB--&gt;&gt;T1: version A 或 B</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>旧版本最终由 VACUUM 回收。长事务、闲置事务和长时间复制槽会阻止回收，导致表膨胀与事务 ID 风险。事务应短小，应用设置 <code>idle_in_transaction_session_timeout</code> 等保护，并监控最老事务。</p><h2 id="_3-postgresql-18-的隔离级别" tabindex="-1">3. PostgreSQL 18 的隔离级别 <a class="header-anchor" href="#_3-postgresql-18-的隔离级别" aria-label="Permalink to &quot;3. PostgreSQL 18 的隔离级别&quot;">​</a></h2><h3 id="read-committed-默认" tabindex="-1">Read Committed（默认） <a class="header-anchor" href="#read-committed-默认" aria-label="Permalink to &quot;Read Committed（默认）&quot;">​</a></h3><p>每条语句开始取得新快照。同一事务两次 SELECT 可能看到别的事务在中间提交的新值（不可重复读）。一条 UPDATE 查找目标时会处理并发变化，并可能重新检查 WHERE 条件。</p><p>适合大多数短事务，但“先读后写”的跨语句不变量需要条件写、锁或更高隔离保护。</p><h3 id="repeatable-read" tabindex="-1">Repeatable Read <a class="header-anchor" href="#repeatable-read" aria-label="Permalink to &quot;Repeatable Read&quot;">​</a></h3><p>事务内普通查询看到事务开始时一致快照（准确说首次非事务控制语句建立的快照），避免不可重复读；PostgreSQL 实现还不会出现标准允许的幻读。但并发更新可能导致 serialization failure，应用必须重试整个事务。</p><h3 id="serializable" tabindex="-1">Serializable <a class="header-anchor" href="#serializable" aria-label="Permalink to &quot;Serializable&quot;">​</a></h3><p>目标是让成功提交的并发事务效果等价于某种串行顺序。PostgreSQL 使用 Serializable Snapshot Isolation，跟踪读写依赖，发现危险结构时中止一个事务并返回 <code>40001</code>。它不等于把所有事务排队，也不取消显式锁需要。</p><p>只把隔离级别字符串改为 serializable 而不实现有界的整事务重试，会把并发冲突变成用户错误。</p><h3 id="read-uncommitted" tabindex="-1">Read Uncommitted <a class="header-anchor" href="#read-uncommitted" aria-label="Permalink to &quot;Read Uncommitted&quot;">​</a></h3><p>PostgreSQL 把它当 Read Committed 处理，不提供脏读。SQLite 和 MySQL 的具体默认、快照与锁行为不同，不能把 PostgreSQL 结论直接套用。</p><h2 id="_4-典型并发现象" tabindex="-1">4. 典型并发现象 <a class="header-anchor" href="#_4-典型并发现象" aria-label="Permalink to &quot;4. 典型并发现象&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>含义</th><th style="text-align:right;">PostgreSQL RC</th><th style="text-align:right;">RR</th><th style="text-align:right;">Serializable</th></tr></thead><tbody><tr><td>脏读</td><td>读到未提交值</td><td style="text-align:right;">不会</td><td style="text-align:right;">不会</td><td style="text-align:right;">不会</td></tr><tr><td>不可重复读</td><td>同事务重复读值变化</td><td style="text-align:right;">可能</td><td style="text-align:right;">不会</td><td style="text-align:right;">不会</td></tr><tr><td>幻读</td><td>条件查询出现新匹配行</td><td style="text-align:right;">可能</td><td style="text-align:right;">不会（PG实现）</td><td style="text-align:right;">不会</td></tr><tr><td>丢失更新</td><td>基于旧读覆盖新值</td><td style="text-align:right;">需设计防止</td><td style="text-align:right;">可能报并发更新错误</td><td style="text-align:right;">冲突事务中止</td></tr><tr><td>写偏差</td><td>两事务读共同条件、写不同对象破坏不变量</td><td style="text-align:right;">可能</td><td style="text-align:right;">可能</td><td style="text-align:right;">检测并中止之一</td></tr></tbody></table><p>约束优先于应用检查。唯一、外键、CHECK、排除约束能表达的不变量应放数据库。跨多行复杂不变量可用 serializable、显式锁或重新建模为可锁单行。</p><h2 id="_5-行级锁" tabindex="-1">5. 行级锁 <a class="header-anchor" href="#_5-行级锁" aria-label="Permalink to &quot;5. 行级锁&quot;">​</a></h2><p><code>SELECT ... FOR UPDATE</code> 锁定选中行，阻止其他事务修改/删除或取得冲突锁。其他模式包括 <code>FOR NO KEY UPDATE</code>、<code>FOR SHARE</code>、<code>FOR KEY SHARE</code>，冲突强度不同。</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">BEGIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> available</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> inventory</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sku </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;sku_8&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FOR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> UPDATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UPDATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> inventory</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> available </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> available </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sku </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;sku_8&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COMMIT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>锁只保护实际锁到的行。查询“没有任何预约”然后锁零行，不能阻止另一个事务插入新预约；需要唯一/排除约束、锁定共同父行或 serializable。</p><p><code>NOWAIT</code> 在不能立即获得锁时失败；<code>SKIP LOCKED</code> 跳过被锁行，适合多个 worker 领取队列，不适合需要完整一致视图的普通查询。</p><h2 id="_6-表级锁与-ddl" tabindex="-1">6. 表级锁与 DDL <a class="header-anchor" href="#_6-表级锁与-ddl" aria-label="Permalink to &quot;6. 表级锁与 DDL&quot;">​</a></h2><p>PostgreSQL 表锁从 ACCESS SHARE 到 ACCESS EXCLUSIVE 有多种模式。普通 SELECT 取得 ACCESS SHARE；许多 ALTER TABLE 操作需要较强锁。<code>ACCESS EXCLUSIVE</code> 与所有模式冲突。即使 DDL 本身很快，也可能排在长事务后等待，而后续查询又排在 DDL 后形成阻塞队列。</p><p>迁移前设置短 <code>lock_timeout</code>，监控阻塞者，在低风险窗口执行。不要误以为 <code>CREATE INDEX CONCURRENTLY</code> 没有任何锁或失败状态；它减少写阻塞，但耗时更长且失败可能留下 INVALID 索引。</p><h2 id="_7-死锁机制" tabindex="-1">7. 死锁机制 <a class="header-anchor" href="#_7-死锁机制" aria-label="Permalink to &quot;7. 死锁机制&quot;">​</a></h2><p>死锁是事务形成等待环：</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T1[&quot;T1 持有 A，等待 B&quot;] --&gt; T2[&quot;T2 持有 B，等待 A&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T2 --&gt; T1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>PostgreSQL 检测后中止一个事务，SQLSTATE <code>40P01</code>。避免方法：所有路径按稳定顺序锁资源；缩短事务；先确定目标再锁；不要在持锁事务中调用慢外部服务。死锁仍可能发生，应用应将其作为可重试的整事务失败。</p><p>锁等待与死锁不同。单向长等待不会形成环，要通过 <code>lock_timeout</code>、<code>statement_timeout</code>、监控和终止阻塞源处理。</p><h2 id="_8-保存点与失败状态" tabindex="-1">8. 保存点与失败状态 <a class="header-anchor" href="#_8-保存点与失败状态" aria-label="Permalink to &quot;8. 保存点与失败状态&quot;">​</a></h2><p>PostgreSQL 事务中任一语句报错后，事务进入 aborted 状态，必须 ROLLBACK；若要局部恢复，事先建立 SAVEPOINT：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BEGIN;</span></span>
<span class="line"><span>SAVEPOINT before_optional;</span></span>
<span class="line"><span>INSERT INTO optional_events ...;</span></span>
<span class="line"><span>-- 若失败：ROLLBACK TO SAVEPOINT before_optional;</span></span>
<span class="line"><span>COMMIT;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>保存点不是把业务不变量拆成可忽略错误的工具。应用驱动的嵌套事务通常由 savepoint 模拟，需清楚最终仍由外层提交决定。</p><h2 id="_9-重试事务的正确方式" tabindex="-1">9. 重试事务的正确方式 <a class="header-anchor" href="#_9-重试事务的正确方式" aria-label="Permalink to &quot;9. 重试事务的正确方式&quot;">​</a></h2><p>可序列化失败 <code>40001</code>、死锁 <code>40P01</code> 和部分连接错误可能重试，但必须重新开始整个事务并重新读取。仅重试最后一条 UPDATE 会使用旧决策。使用最大次数、总 deadline 和抖动；外部副作用放事务外并由 outbox/幂等协调。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>for attempt within budget:</span></span>
<span class="line"><span>  begin new transaction</span></span>
<span class="line"><span>  read current state</span></span>
<span class="line"><span>  validate invariant</span></span>
<span class="line"><span>  write</span></span>
<span class="line"><span>  commit</span></span>
<span class="line"><span>  if 40001 or 40P01: rollback, jitter, retry whole closure</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>事务 closure 可能多次运行，内部不能直接发送邮件、扣第三方款或生成不可重复随机业务结果。需要把确定结果落库或使用 outbox。</p><h2 id="_10-完整案例-值班医生写偏差" tabindex="-1">10. 完整案例：值班医生写偏差 <a class="header-anchor" href="#_10-完整案例-值班医生写偏差" aria-label="Permalink to &quot;10. 完整案例：值班医生写偏差&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>规则：至少一名医生处于 on_call。当前 A、B 都值班。两个 Repeatable Read 事务同时读取总数 2，A 将自己设为 false，B 也将自己设为 false；它们更新不同的行。</p><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ol><li>T1 和 T2 在同一快照看到两人值班。</li><li>T1 更新 A，T2 更新 B，行锁不冲突。</li><li>Repeatable Read 下两者可能都提交，规则被破坏。</li><li>改为 Serializable，SSI 检测读写依赖危险结构并中止一个事务。</li><li>应用捕获 <code>40001</code>，重新执行被中止事务；新快照看到只剩一人，因此拒绝下线。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>最终至少一人值班。也可重新建模，把班次的最小人数/版本放在共同父行并锁定，或用可表达的数据库约束；选择取决于访问模式和争用。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>两连接并发运行相同场景数百次，Repeatable Read 能复现风险。</li><li>Serializable 下不会提交非法最终状态，且应用对 40001 有界重试。</li><li>重试 closure 内没有外部副作用。</li><li>事务时长、重试率和最老事务有指标。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若只在 UPDATE 前运行 <code>SELECT count(*)</code> 而仍用 Read Committed，两事务都可能通过。若分别 <code>FOR UPDATE</code> 自己的行，也没有锁住共同不变量。修正为锁定代表规则的共同对象，或使用 Serializable 并重试整个事务。</p><h2 id="_11-锁诊断" tabindex="-1">11. 锁诊断 <a class="header-anchor" href="#_11-锁诊断" aria-label="Permalink to &quot;11. 锁诊断&quot;">​</a></h2><p>定位阻塞时查看 <code>pg_stat_activity</code> 的事务开始、query、wait event，以及 <code>pg_blocking_pids(pid)</code>。终止连接是最后手段：取消当前语句与终止 session 影响不同，终止会回滚其事务。</p><p>记录规范化 SQL 和业务操作，不在共享诊断输出泄露敏感参数。重点找 idle in transaction、长报表事务、未提交迁移和不同代码路径的锁顺序。</p><h2 id="_12-常见错误" tabindex="-1">12. 常见错误 <a class="header-anchor" href="#_12-常见错误" aria-label="Permalink to &quot;12. 常见错误&quot;">​</a></h2><ul><li>将 ACID 的一致性理解为数据库自动知道全部业务规则。</li><li>认为 PostgreSQL Repeatable Read 与所有数据库完全相同。</li><li>Serializable 不实现重试。</li><li>只锁已有行，却要保护“没有行”的条件。</li><li>事务里调用慢外部 API，长时间持锁。</li><li>发生错误后继续使用已 aborted 的事务。</li><li>捕获死锁只重试最后一条语句。</li><li>长事务阻止 VACUUM，却只扩容磁盘。</li></ul><h2 id="_13-练习" tabindex="-1">13. 练习 <a class="header-anchor" href="#_13-练习" aria-label="Permalink to &quot;13. 练习&quot;">​</a></h2><p>分别实现账户转账、值班医生和队列领取。为每个场景选择约束、条件 UPDATE、显式锁或 Serializable，并写两连接并发测试。</p><p>完成标准：转账守恒且余额不为负；写偏差场景不能产生非法状态；队列使用 <code>SKIP LOCKED</code> 不重复领取；死锁采用稳定锁顺序并有整事务重试；监控能定位 idle transaction 和阻塞链。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.postgresql.org/docs/18/transaction-iso.html" target="_blank" rel="noreferrer">PostgreSQL 18: Transaction Isolation</a>（访问日期：2026-07-17）</li><li><a href="https://www.postgresql.org/docs/18/explicit-locking.html" target="_blank" rel="noreferrer">PostgreSQL 18: Explicit Locking</a>（访问日期：2026-07-17）</li><li><a href="https://www.postgresql.org/docs/18/mvcc-intro.html" target="_blank" rel="noreferrer">PostgreSQL 18: MVCC Introduction</a>（访问日期：2026-07-17）</li><li><a href="https://www.postgresql.org/docs/18/routine-vacuuming.html" target="_blank" rel="noreferrer">PostgreSQL 18: Routine Vacuuming</a>（访问日期：2026-07-17）</li><li><a href="https://www.postgresql.org/docs/release/18.4/" target="_blank" rel="noreferrer">PostgreSQL 18.4 Release Notes</a>（访问日期：2026-07-17）</li></ul>`,64)])])}const k=s(t,[["render",l]]);export{b as __pageData,k as default};
